func googlePrivatePath(kind, filename string) string {
	configDir, err := os.UserConfigDir()
	if err != nil {
		home, homeErr := os.UserHomeDir()
		if homeErr != nil {
			return filename
		}
		configDir = filepath.Join(home, ".config")
	}
	return filepath.Join(configDir, "printing-press", "google-private", kind, filename)
}

