	// Resolve config path
	path := configPath
	if path == "" {
		path = os.Getenv("YOUTUBE_CONFIG")
	}
	if path == "" {
		home, _ := os.UserHomeDir()
		path = filepath.Join(home, ".config", "youtube-pp-cli", "config.toml")
	}
	cfg.Path = path

	// Try to load config file
	data, err := os.ReadFile(path)
	if err == nil {
		if err := toml.Unmarshal(data, cfg); err != nil {
			return nil, fmt.Errorf("parsing config %s: %w", path, err)
		}
	} else if !errors.Is(err, os.ErrNotExist) {
		return nil, fmt.Errorf("reading config %s: %w", path, err)
	}

	if cfg.CredentialsPath == "" {
		cfg.CredentialsPath = DefaultCredentialsPath
	}
	if cfg.TokenPath == "" {
		cfg.TokenPath = DefaultTokenPath
	}
	if v := os.Getenv("YOUTUBE_PP_CREDENTIALS"); v != "" {
		cfg.CredentialsPath = v
	}
	if v := os.Getenv("YOUTUBE_PP_TOKEN"); v != "" {
		cfg.TokenPath = v
	}

	// Env var overrides
	if v := os.Getenv("YOUTUBE_DATA_OAUTH2C"); v != "" {
		cfg.YoutubeDataOauth2c = v
		cfg.AuthSource = "env:YOUTUBE_DATA_OAUTH2C"
	}

	// Label config-file-derived credentials so doctor can distinguish
	// credentials persisted on disk from no credentials at all.
	if cfg.AuthSource == "" && (cfg.AuthHeaderVal != "" || cfg.AccessToken != "") {
		cfg.AuthSource = "config"
	}
	if cfg.AuthSource == "" && cfg.YoutubeDataOauth2c != "" {
		cfg.AuthSource = "config"
	}

	// Base URL override (used by printing-press verify to point at mock/test servers)
	if v := os.Getenv("YOUTUBE_BASE_URL"); v != "" {
		cfg.BaseURL = v
	}
	if v := os.Getenv("YOUTUBE_AUTHORIZATION_URL"); v != "" {
		cfg.AuthorizationURL = v
	}
	if v := os.Getenv("YOUTUBE_TOKEN_URL"); v != "" {
		cfg.TokenURL = v
	}
	return cfg, nil
